let defaultParts = {{defaultParts}}
let thousand = defaultParts.find(part => part.type === 'group').value
let decimal = defaultParts.find(part => part.type === 'decimal').value

return new Promise(function (resolve, reject) {
  const url = '{{startUrl}}' + 'wp-json/wc-automation-helper/woocommerce-settings/?currency={{currency}}&price_thousand_sep='+thousand+'&price_decimal_sep='+decimal+'&price_num_decimals={{decimals}}&currency_pos={{position}}';
  const username = '{{woo_user}}';
  const password = '{{woo_pass}}';
  let headers = new Headers();
  headers.set('Content-Type', 'application/json');
  headers.set('Authorization', 'Basic ' + btoa(username + ":" + password));
  fetch(url, {method:'POST', headers: headers, credentials: 'omit'})
  .then(function(response) {
    if (response.ok) {
      resolve(response.json())
    } else {
      resolve([])
    } 
  })
  })
